+    // 8. cumsum() - Cumulative sum
+    .{
+        .c_func_name = "numpy_cumsum_impl",
+        .py_func_name = "numpy.cumsum",
+        .args = &[_]ArgSpec{
+            .{ .name = "array", .py_type = .numpy_array, .c_type = []const f64 },
